- (void)dialogueBaseCell:(WBDialogueBaseCell *)cell didTriggerRoute:(NSURL *)routePath {
    NSURLComponents *components = [NSURLComponents componentsWithURL:routePath resolvingAgainstBaseURL:NO]; // 解析原始URL
    NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new]; // 获取现有查询参数

    // 添加msgId参数，重构URL，并执行新路由
    NSURLQueryItem *msgIdItem = [NSURLQueryItem queryItemWithName:@"msgId" value:[NSString stringWithFormat:@"%ld", (long)cell.msgId]];
    [queryItems addObject:msgIdItem];
    components.queryItems = queryItems;
    NSURL *modifiedURL = components.URL;
    [WBRouteManager.sharedManager performRoute:modifiedURL sourceInterface:@"support/recents"];
}这个函数是干嘛的

