@interface WBDialogueBaseCell ()

@property(nonatomic, strong) UILabel *dateLabel;
@property(nonatomic, strong) UIImageView *iconImageView;
@property(nonatomic, strong) UIImageView *mainImageView;

@property(nonatomic, strong) UITableView *operationListView;
@property(nonatomic, assign) CGRect initialFrame;

@end

@implementation WBDialogueBaseCell

static NSString * const operationCellReuseId = @"operationCell";

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)reuseIdentifier {
    if (self = [super initWithStyle:UITableViewCellStyleSubtitle reuseIdentifier:reuseIdentifier]) {
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.backgroundColor = [UIColor whiteColor];
        self.layer.cornerRadius = WBRpt(12.0);

        self.textLabel.font = WBDialogueTitleFont;
        self.textLabel.textColor = WBTextColor1;

        self.detailTextLabel.font = WBDialogueContentFont;
        self.detailTextLabel.textColor = WBTextColor2;
    }
    return self;
}

- (void)setFrame:(CGRect)frame {
    _initialFrame = frame;
    frame = [self.dialogueProvider cellFrameWithInitialFrame:frame];
    [super setFrame:frame];
}

- (CGRect)frame {
    return _initialFrame;
}

- (void)layoutSubviews {
    [super layoutSubviews];
    _operationListView.frame = self.contentView.bounds;
    _dateLabel.frame = self.dialogueProvider.dateLabelFrame;
    _iconImageView.frame = self.dialogueProvider.iconImageViewFrame;
    self.textLabel.frame = self.dialogueProvider.textLabelFrame;
    self.detailTextLabel.frame = self.dialogueProvider.detailTextLabelFrame;
    _mainImageView.frame = self.dialogueProvider.imageViewFrame;
//    self.imageView.frame = self.dialogueProvider.imageViewFrame;
}

- (void)setDialogueProvider:(WBDialogueCellBaseProvider *)dialogueProvider {
    _dialogueProvider = dialogueProvider;
    self.textLabel.text = dialogueProvider.dialogue.title;
    self.textLabel.numberOfLines = dialogueProvider.hasShowDetailArticleOperation ? WBDialogueTitleMaxLineCountWhenHasLink : 0;

    self.detailTextLabel.text = dialogueProvider.dialogue.content;
    self.detailTextLabel.numberOfLines = dialogueProvider.hasShowDetailArticleOperation ? WBDialogueContentMaxLineCountWhenHasLink : 0;

    if (dialogueProvider.dialogue.imageNameOrUrl) {
        UIImage *placeholderImage = [UIImage wb_imageWithColor:WBShadowColor size:dialogueProvider.imageSize];
        self.mainImageView.image = placeholderImage;
        self.mainImageView.wb_imageURL = [NSURL URLWithString:dialogueProvider.dialogue.imageNameOrUrl];
    }

    if (dialogueProvider.isHideDate) {
        _dateLabel.hidden = YES;
    } else {
        self.dateLabel.hidden = NO;
        self.dateLabel.text = dialogueProvider.createDateString;
    }

    if (dialogueProvider.dialogue.iconURL) {
        self.iconImageView.hidden = NO;
        self.iconImageView.wb_imageURL = [NSURL URLWithString:dialogueProvider.dialogue.iconURL];
    } else {
        _iconImageView.hidden = YES;
    }

    if (dialogueProvider.dialogue.operations.count) {
        self.operationListView.hidden = NO;
        [self.operationListView reloadData];
    } else {
        _operationListView.hidden = YES;
    }
}

- (void)gestureDetected:(id)sender {
    WBRichMessageLinkModel *operation = self.dialogueProvider.dialogue.operations.firstObject;
    if (operation && self.delegate && [self.delegate respondsToSelector:@selector(dialogueBaseCell:didSelectedOperation:)]) {
        [self.delegate dialogueBaseCell:self didSelectedOperation:operation];
    } else if (self.dialogueProvider.dialogue.imageNameOrUrl) {
        WBImagePreviewViewController *previewVC = [[WBImagePreviewViewController alloc] initWithImageURL:self.dialogueProvider.dialogue.imageNameOrUrl];
        UIViewController *currentVC = [WBAppManager getUIApplicationCurrentViewController];
        if (currentVC) {
            [currentVC presentViewController:previewVC animated:YES completion:nil];
        }
    }
}

#pragma mark - Lazy load

- (UITableView *)operationListView {
    if (_operationListView == nil) {
        _operationListView = [[UITableView alloc] initWithFrame:CGRectZero style:UITableViewStyleGrouped];
        _operationListView.separatorStyle = UITableViewCellSeparatorStyleNone;
        _operationListView.scrollEnabled = NO;
        _operationListView.backgroundColor = [UIColor clearColor];
        _operationListView.rowHeight = WBDialogueCellOperationListRowHeight;
        [_operationListView registerClass:[WBDialogueOperationCell class] forCellReuseIdentifier:operationCellReuseId];
        _operationListView.delegate = self;
        _operationListView.dataSource = self;
        [self.contentView addSubview:_operationListView];
        [self.contentView bringSubviewToFront:self.textLabel];
        [self.contentView bringSubviewToFront:self.detailTextLabel];
//        [self.contentView bringSubviewToFront:self.imageView];
        [self.contentView bringSubviewToFront:self.mainImageView];
        if (_iconImageView) {
            [self.contentView bringSubviewToFront:_iconImageView];
        }
    }
    return _operationListView;
}

- (UILabel *)dateLabel {
    if (_dateLabel == nil) {
        _dateLabel = [[UILabel alloc] init];
        _dateLabel.textAlignment = NSTextAlignmentCenter;
        _dateLabel.font = WBDialogueDateFont;
        _dateLabel.textColor = WBTextColor3;
        [self addSubview:_dateLabel];
    }
    return _dateLabel;
}

- (UIImageView *)mainImageView {
    if (_mainImageView == nil) {
        _mainImageView = [[UIImageView alloc] init];
        _mainImageView.layer.cornerRadius = WBRpt(8.0);
        _mainImageView.layer.masksToBounds = YES;
        [_mainImageView setUserInteractionEnabled:TRUE];
        UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] init];
        [tap setNumberOfTapsRequired:1];
        [tap addTarget:self action:@selector(gestureDetected:)];
        [_mainImageView addGestureRecognizer:tap];
        [self addSubview:_mainImageView];
    }
    return _mainImageView;
}

- (UIImageView *)iconImageView {
    if (_iconImageView == nil) {
        _iconImageView = [[UIImageView alloc] init];
        _iconImageView.layer.cornerRadius = WBRpt(8.0);
        _iconImageView.layer.masksToBounds = YES;
        [self addSubview:_iconImageView];
    }
    return _iconImageView;
}

#pragma mark - Table view data source

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    return self.dialogueProvider.dialogue.operations.count;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    WBDialogueOperationCell *cell = [tableView dequeueReusableCellWithIdentifier:operationCellReuseId];
    WBRichMessageLinkModel *operation = self.dialogueProvider.dialogue.operations[indexPath.row];
    cell.textLabel.text = operation.label;
    return cell;
}

#pragma mark - Table view delegate

- (CGFloat)tableView:(UITableView *)tableView heightForHeaderInSection:(NSInteger)section {
    return self.dialogueProvider.mainContentHeight;
}

- (UIView *)tableView:(UITableView *)tableView viewForHeaderInSection:(NSInteger)section {
    return [[UIView alloc] init];
}

- (void)tableView:(UITableView *)tableView didSelectRowAtIndexPath:(NSIndexPath *)indexPath {
    WBRichMessageLinkModel *operation = self.dialogueProvider.dialogue.operations[indexPath.row];
    if (self.delegate && [self.delegate respondsToSelector:@selector(dialogueBaseCell:didSelectedOperation:)]) {
        [self.delegate dialogueBaseCell:self didSelectedOperation:operation];
    }
}

@end

