- (instancetype)initWithDict:(NSDictionary *)dict sourceInterface:(nullable NSString *)sourceInterface {
    if (self = [super initWithDict:dict sourceInterface:sourceInterface]) {
        self.fromAdmin = [dict[@"admin"] boolValue];

        NSString *type = dict[@"type"];
        if ([type isEqualToString:@"text"]) {
            self.type = WBFeedbackTypeText;
            NSParameterAssert(dict[@"text"] && dict[@"text"] != [NSNull null]);
            self.content = dict[@"text"];
        } else if ([type isEqualToString:@"image"]) {
            self.type = WBFeedbackTypeImage;
            NSParameterAssert(dict[@"image"] && dict[@"image"] != [NSNull null]);
            self.imageNameOrUrl = [dict[@"image"] lowercaseString];
        } else if ([type isEqualToString:@"rich_message"]) {
            self.type = WBFeedbackTypeRich;
        } else if ([type isEqualToString:@"route"]) {
            self.type = WBFeedbackTypeRoute;
            self.title = dict[@"title"];
            self.content = dict[@"desc"];
            self.route = [NSURL URLWithString:dict[@"route"]];
        }
        self.msgId = [(NSNumber*)dict[@"id"] intValue];

    }
    return self;
}

@end

