- (void)refreshFeedbacks {
    NSParameterAssert([[NSOperationQueue currentQueue] isEqual:[NSOperationQueue mainQueue]]);
    if (self.isFeedbackRefreshing) return;
    self.feedbackRefreshing = true;
    [self.refreshControl beginRefreshing];
    NSInteger fromId = 0;
    if ([self.feedbackCellProviders count] > 0) {
        fromId = self.feedbackCellProviders.firstObject.feedback.msgId;
    }
    [[WBNetworkManager defaultManager] getRecentFeedbacksWithCount:10 from:fromId callback:^(NSArray<WBFeedbackModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        NSParameterAssert([[NSOperationQueue currentQueue] isEqual:[NSOperationQueue mainQueue]]);
        NSParameterAssert(!error);
        if (error) {
            //TODO: handle err.
        }
        self.feedbackRefreshing = false;
        [self.refreshControl endRefreshing];
//        self.refreshControl.attributedTitle = [[NSAttributedString alloc] initWithString:@"下拉加载更多"];
        if ([feedbacks count]) {
            if (fromId == 0) {
                [self addNewFeedbacksToTableView:feedbacks scrollToBottomAnimated:YES];
            } else {
                [self insertFeedbacksToTableView:feedbacks];
            }
        } else {
            self.previousFeedbackAllLoaded = true;
        }
        if (self.postFeedbackLoadAction) {
            self.postFeedbackLoadAction();
            self.postFeedbackLoadAction = nil;
        }
        [self startPullNewFeedbackWithAutomaticFrequency];
    }];
}


