- (void)systemKeyboardWillShow:(NSNotification *)notification {
    WBLogFunc();
    if (!self.typeBoxShouldRespondToSystemKeyboardNotification) return;
    NSDictionary *userInfo = notification.userInfo;
    NSTimeInterval duration = [userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    CGRect frameEnd = [userInfo[UIKeyboardFrameEndUserInfoKey] CGRectValue];
    CGFloat keyboardH = frameEnd.size.height;
    [self moveUpTypeBoxAboveSystemKeyboardWithDuration:duration keyboardHeight:keyboardH];
    [self scrollToLastFeedbackAnimated:YES];
}

- (void)systemKeyboardWillHide:(NSNotification *)notification {
    WBLogFunc();
    if (!self.typeBoxShouldRespondToSystemKeyboardNotification) return;
    NSDictionary *userInfo = notification.userInfo;
    NSTimeInterval duration = [userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    [self moveDownTypeBoxToScreenBottomWithDuration:duration];
}

