// To wind or unwind type box depends on whether the more button on box view is selected. If selected, unwind to show more selections.
- (void)toggleTypeBox {
    // Load type box only once and avoid to init frame in the animation block.
    if (self.typeBox.moreButton.isSelected && !self.typeBoxAlbumButtonLoaded) {
        [self.typeBox albumButton];
        [self.typeBox.albumButton addTarget:self action:@selector(typeBoxAlbumButtonClicked) forControlEvents:UIControlEventTouchUpInside];
    }
    [UIView animateWithDuration:0.25 animations:^{
        CGFloat boxViewUnwindH = WBRpt(150.0);
        self.typeBox.wb_height = self.typeBox.moreButton.isSelected ? boxViewUnwindH : WBFeedbackTypeBoxNormalHeight;
        self.typeBox.wb_bottom = self.view.wb_height;
        self.typeBox.albumButton.alpha = self.typeBox.moreButton.isSelected;
        [self adjustViewsAboveTypeBox];
        if (self.typeBox.moreButton.isSelected) {
            [self scrollToLastFeedbackAnimated:YES];
        }
    }];
}

- (void)windTypeBoxIfNeeded {
    if (!self.typeBox.moreButton.isSelected) return;
    self.typeBox.moreButton.selected = NO;
    [self toggleTypeBox];
}

