- (NSMutableArray<WBFeedbackCellProvider *> *)wrapFeedbackModelsWithProviders:(NSArray<WBFeedbackModel *> *)feedbacks {
    NSMutableArray<WBFeedbackCellProvider *> *providers = [NSMutableArray arrayWithCapacity:feedbacks.count];
    WBFeedbackModel *previousFeedback = [self.feedbackCellProviders lastObject].feedback;
    for (WBFeedbackModel *feedback in feedbacks) {
        WBFeedbackCellProvider *provider = [[WBFeedbackCellProvider alloc] initWithFeedback:feedback previousFeedback:previousFeedback];
        [providers addObject:provider];
        previousFeedback = feedback;
    }
    return providers;
}

- (void)addNewFeedbacksToTableView:(NSArray<WBFeedbackModel *> *)feedbacks scrollToBottomAnimated:(BOOL)animated {
    NSArray<WBFeedbackCellProvider *> *newProviders = [self wrapFeedbackModelsWithProviders:feedbacks];
    [self.feedbackCellProviders addObjectsFromArray:newProviders];
    [self.tableView reloadData];
    [self scrollToLastFeedbackAnimated:animated];
}

- (void)insertFeedbacksToTableView:(NSArray<WBFeedbackModel *> *)feedbacks {
    NSArray<WBFeedbackCellProvider *> *newProviders = [self wrapFeedbackModelsWithProviders:feedbacks];
    [self.feedbackCellProviders insertObjects:newProviders atIndex:0];
    CGFloat offsetY = self.tableView.contentOffset.y;
//    NSAssert(offsetY <= 0, ([NSString stringWithFormat:@"offsetY = %f", offsetY]));
    [self.tableView reloadData];
    [self.tableView scrollToRow:feedbacks.count inSection:0 atScrollPosition:UITableViewScrollPositionTop animated:NO];
    CGPoint contentOffset = self.tableView.contentOffset;
    contentOffset.y += offsetY;
    self.tableView.contentOffset = contentOffset;
}

