- (void)scrollViewDidScroll:(UIScrollView *)scrollView {
    if (scrollView != self.tableView) return;
    if (self.refreshControl.isRefreshing) return; // Prevent method is called by [UIRefreshControl endRefreshing].
    if (self.isFeedbackRefreshing) return;
    if (self.isPreviousFeedbackAllLoaded) return;
    if (self.tableView.contentOffset.y < 0) {
        [self refreshFeedbacks];
    }
}

- (void)scrollViewWillBeginDragging:(UIScrollView *)scrollView {
    if (scrollView != self.tableView) return;
    [self.typeBox.textField resignFirstResponder];
    [self windTypeBoxIfNeeded];
}

