@implementation WBFeedbackCellProvider

- (instancetype)initWithFeedback:(WBFeedbackModel *)feedback previousFeedback:(nonnull WBFeedbackModel *)previousFeedback {
    NSMutableArray *discardedItems = [NSMutableArray array];
    for(WBRichMessageLinkModel *link in feedback.operations) {
        if (link.type == WBRichMessageLinkTypeExit || link.type == WBRichMessageLinkTypeDismiss) {
            [discardedItems addObject:link];
        }
    }
    [feedback.operations removeObjectsInArray:discardedItems];
    if (self = [super initWithDialogue:feedback previousDialogue:previousFeedback]) {
        self.mainContentMaxWidth = WBRpt(260.0);
    }
    return self;
}

- (WBFeedbackModel *)feedback {
    return (WBFeedbackModel *)[super dialogue];
}

- (CGRect)dateLabelFrame {
    // When feedback type is 'user', the cell is on the rightside, and the date label frame for feedback type 'official' and 'faq' (In which case cell displays on the leftside) doesn't work and needs to update.
    CGRect dateLabelFrame = [super dateLabelFrame];
    if (!self.feedback.isFromAdmin) {
        dateLabelFrame.origin.x = self.cellWidth - dateLabelFrame.size.width;
        self.dateLabelFrame = dateLabelFrame;
    }
    return dateLabelFrame;
}

- (CGFloat)cellWidth {
    if (_cellWidth == 0.0) {
        if (self.feedback.operations.count) {
            _cellWidth = self.mainContentMaxWidth + WBDefaultPadding * 2;
        } else {
            _cellWidth = MAX(CGRectGetMaxX(self.textLabelFrame), MAX(CGRectGetMaxX(self.detailTextLabelFrame), CGRectGetMaxX(self.imageViewFrame))) + WBDefaultPadding;
        }
    }
    return _cellWidth;
}

- (CGRect)cellFrameWithInitialFrame:(CGRect)frame {
    frame = [super cellFrameWithInitialFrame:frame];
    frame.size.width = self.cellWidth;
    if (self.feedback.isFromAdmin) {
        frame.origin.x = WBDefaultPadding;
    } else {
        frame.origin.x = WBScreenWidth - WBDefaultPadding - frame.size.width;
    }
    return frame;
}

