#import "WBDialogueCellBaseProvider.h"

@implementation WBDialogueCellBaseProvider

- (instancetype)initWithDialogue:(WBRichMessageModel *)dialogue previousDialogue:(WBRichMessageModel * _Nullable)previousDialogue {
    if (self = [super init]) {
        _dialogue = dialogue;
        if (previousDialogue) {
            NSDateComponents *components = [[NSCalendar currentCalendar] components:NSCalendarUnitMinute fromDate:previousDialogue.createDate toDate:dialogue.createDate options:NSCalendarWrapComponents];
            _hideDate = components.minute <= 2;
        } else {
            _hideDate = NO;
        }
        // Set up 'hasShowDetailArticleOperation' property.
        for (WBRichMessageLinkModel *operation in dialogue.operations) {
            if (operation.type == WBRichMessageLinkTypeWebview) {
                _hasShowDetailArticleOperation = YES;
                break;
            }
        }
    }
    return self;
}

- (NSString *)createDateString {
    if (_createDateString == nil) {
        NSDate *createDate = self.dialogue.createDate;
        _createDateString = [[NSDateFormatter wb_uiDateFormatter] stringFromDate:createDate];
    }
    return _createDateString;
}

- (CGSize)imageSize {
    if (CGSizeEqualToSize(_imageSize, CGSizeZero) && self.dialogue.imageNameOrUrl) {
        NSString *urlStr = [self.dialogue.imageNameOrUrl stringByDeletingLastPathComponent];
        NSString *sizeStr = urlStr.lastPathComponent;
        NSArray *sizeComps = [sizeStr componentsSeparatedByString:@"x"];
        CGFloat width = [sizeComps[0] floatValue];
        CGFloat height = [sizeComps[1] floatValue];

        if (width > self.mainContentMaxWidth) {
            CGFloat ratio = height / width;
            width = self.mainContentMaxWidth;
            height = width * ratio;
        }

        _imageSize = CGSizeMake(width, height);
    }
    return _imageSize;
}

- (CGSize)iconSize {
    if (CGSizeEqualToSize(_iconSize, CGSizeZero) && self.dialogue.iconURL) {
        CGFloat iconSize = WBRpt(32.0);
        _iconSize = CGSizeMake(iconSize, iconSize);
    }
    return _iconSize;
}

- (CGRect)dateLabelFrame {
    if (CGRectIsEmpty(_dateLabelFrame) && !self.isHideDate) {
        CGFloat dateLabelW = WBScreenWidth - WBDefaultPadding * 2;
        CGFloat dateLabelH = WBRpt(36.0);
        CGFloat dateLabelY = -dateLabelH;
        _dateLabelFrame = CGRectMake(0.0, dateLabelY, dateLabelW, dateLabelH);
    }
    return _dateLabelFrame;
}

- (CGRect)iconImageViewFrame {
    if (CGRectIsEmpty(_iconImageViewFrame) && self.dialogue.iconURL) {
        CGFloat iconX = WBDefaultPadding;
        CGFloat iconY;
        if (self.dialogue.title) {
            CGFloat textLabelCenterY = self.textLabelFrame.origin.y + self.textLabelFrame.size.height * 0.5;
            iconY = textLabelCenterY - self.iconSize.height * 0.5;
        } else {
            iconY = WBDefaultPadding;
        }
        _iconImageViewFrame = CGRectMake(iconX, iconY, self.iconSize.width, self.iconSize.height);
    }
    return _iconImageViewFrame;
}

- (CGRect)textLabelFrame {
    if (CGRectIsEmpty([super textLabelFrame]) && self.dialogue.title) {
        CGSize textLabelSize;
        CGFloat textLabelMaxWidth;
        CGFloat textLabelX;
        CGFloat textLabelY = WBDefaultPadding;
        if (self.dialogue.iconURL) {
            CGFloat iconPadding = WBRpt(8.0);
            textLabelMaxWidth = self.mainContentMaxWidth - self.iconSize.width - iconPadding;
            textLabelX = WBDefaultPadding + (self.mainContentMaxWidth - textLabelMaxWidth);
        } else {
            textLabelMaxWidth = self.mainContentMaxWidth;
            textLabelX = WBDefaultPadding;
        }
        if (self.hasShowDetailArticleOperation) {
            textLabelSize = [self.dialogue.title wb_sizeWithFont:WBDialogueTitleFont maxWidth:textLabelMaxWidth maxLineCount:WBDialogueTitleMaxLineCountWhenHasLink];
        } else {
            textLabelSize = [self.dialogue.title wb_sizeWithFont:WBDialogueTitleFont maxWidth:textLabelMaxWidth];
        }

        self.textLabelFrame = CGRectMake(textLabelX, textLabelY, textLabelSize.width, textLabelSize.height);
    }
    return [super textLabelFrame];
}

- (CGRect)detailTextLabelFrame {
    if (CGRectIsEmpty([super detailTextLabelFrame]) && self.dialogue.content) {
        CGSize detailTextLabelSize;
        if (self.hasShowDetailArticleOperation) {
            detailTextLabelSize = [self.dialogue.content wb_sizeWithFont:WBDialogueContentFont maxWidth:self.mainContentMaxWidth maxLineCount:WBDialogueContentMaxLineCountWhenHasLink];
        } else {
            detailTextLabelSize = [self.dialogue.content wb_sizeWithFont:WBDialogueContentFont maxWidth:self.mainContentMaxWidth];
        }

        CGFloat detailTextLabelY;
        if (self.dialogue.title || self.dialogue.iconURL) {
            detailTextLabelY = MAX(CGRectGetMaxY(self.iconImageViewFrame), CGRectGetMaxY(self.textLabelFrame)) + WBDialogueCellMainContentPadding;
        } else {
            detailTextLabelY = WBDefaultPadding;
        }
        self.detailTextLabelFrame = CGRectMake(WBDefaultPadding, detailTextLabelY, detailTextLabelSize.width, detailTextLabelSize.height);
    }
    return [super detailTextLabelFrame];
}

- (CGRect)imageViewFrame {
    if (CGRectIsEmpty([super imageViewFrame]) && self.dialogue.imageNameOrUrl) {
        CGFloat imageViewY;
        if (self.dialogue.content) {
            imageViewY = CGRectGetMaxY(self.detailTextLabelFrame) + WBDialogueCellMainContentPadding;
        } else if (self.dialogue.title || self.dialogue.iconURL) {
            imageViewY = MAX(CGRectGetMaxY(self.textLabelFrame), CGRectGetMaxY(self.iconImageViewFrame))  + WBDialogueCellMainContentPadding;
        } else {
            imageViewY = WBDefaultPadding;
        }
        self.imageViewFrame = CGRectMake(WBDefaultPadding, imageViewY, self.imageSize.width, self.imageSize.height);
    }
    return [super imageViewFrame];
}

- (CGFloat)mainContentHeight {
    if (_mainContentHeight == 0.0) {
        if (self.dialogue.imageNameOrUrl) {
            self.mainContentHeight = CGRectGetMaxY(self.imageViewFrame) + WBDefaultPadding;
        } else if (self.dialogue.content) {
            self.mainContentHeight = CGRectGetMaxY(self.detailTextLabelFrame) + WBDefaultPadding;
        } else {
            self.mainContentHeight = MAX(CGRectGetMaxY(self.textLabelFrame), CGRectGetMaxY(self.iconImageViewFrame)) + WBDefaultPadding;
        }
    }
    return _mainContentHeight;
}

- (CGFloat)cellHeight {
    if (_cellHeight == 0.0) {
        NSInteger operationCount = self.dialogue.operations.count;
        _cellHeight = self.mainContentHeight + WBDialogueCellOperationListRowHeight * operationCount;
    }
    return _cellHeight;
}

// Calculated by using result of 'cellHeight' method, subclass need not to override.
- (CGFloat)cellInitialHeight {
    if ([super cellInitialHeight] == 0.0) {
        CGFloat cellInitialHeight = self.cellHeight;
        if (self.isHideDate || self.dialogue.createDate == nil) {
            cellInitialHeight += WBDefaultPadding;
        } else {
            CGFloat dateH = self.dateLabelFrame.size.height;
            cellInitialHeight += dateH;
        }
        self.cellInitialHeight = cellInitialHeight;
    }
    return [super cellInitialHeight];
}

// height and y for aimed frame are calculated, subclass only needs to call super and calculte width and x when override.
- (CGRect)cellFrameWithInitialFrame:(CGRect)frame {
    if (self.isHideDate || self.dialogue.createDate == nil) {
        frame.size.height -= WBDefaultPadding;
        frame.origin.y += WBDefaultPadding;
    } else {
        CGFloat dateLabelH = self.dateLabelFrame.size.height;
        frame.size.height -= dateLabelH;
        frame.origin.y += dateLabelH;
    }
    return frame;
}

@end

